import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ProductService } from '../../services/product.service';

@Component({
  selector: 'app-edit-product',
  templateUrl: './edit-product.component.html',
  styleUrls: ['./edit-product.component.css']
})
export class EditProductComponent implements OnInit {
  form: FormGroup;
  loading = false;
  loadingData = true;
  error = '';
  success = '';
  productId!: number;

  categories = ['Electronics', 'Clothing', 'Food & Beverages', 'Furniture', 'Sports', 'Books', 'Health & Beauty', 'Automotive', 'Tools', 'Other'];

  constructor(
    private fb: FormBuilder,
    private productService: ProductService,
    private route: ActivatedRoute,
    private router: Router
  ) {
    this.form = this.fb.group({
      productName: ['', [Validators.required, Validators.minLength(2)]],
      category: ['', Validators.required],
      price: [0, [Validators.required, Validators.min(0)]],
      quantity: [0, [Validators.required, Validators.min(0)]],
      description: ['']
    });
  }

  ngOnInit(): void {
    this.productId = Number(this.route.snapshot.paramMap.get('id'));
    this.productService.getById(this.productId).subscribe({
      next: (p) => {
        this.form.patchValue(p);
        this.loadingData = false;
      },
      error: () => {
        this.error = 'Product not found.';
        this.loadingData = false;
      }
    });
  }

  onSubmit(): void {
    if (this.form.invalid) return;
    this.loading = true;
    this.error = '';

    this.productService.update(this.productId, this.form.value).subscribe({
      next: () => {
        this.success = 'Product updated successfully!';
        this.loading = false;
        setTimeout(() => this.router.navigate(['/products']), 1500);
      },
      error: (err) => {
        this.error = err.error?.message || 'Failed to update product.';
        this.loading = false;
      }
    });
  }

  isInvalid(field: string): boolean {
    const ctrl = this.form.get(field);
    return !!(ctrl?.invalid && ctrl?.touched);
  }
}
<app-sidebar></app-sidebar>
<app-navbar title="Edit Product"></app-navbar>

<main class="main-content">
  <div class="form-card">
    <div class="form-header">
      <h2>Edit Product</h2>
      <a routerLink="/products" class="btn-back">← Back to Products</a>
    </div>

    <div class="loading-spinner" *ngIf="loadingData">Loading product...</div>

    <div class="alert alert-danger" *ngIf="error">{{ error }}</div>
    <div class="alert alert-success" *ngIf="success">✅ {{ success }}</div>

    <form [formGroup]="form" (ngSubmit)="onSubmit()" *ngIf="!loadingData">
      <div class="form-grid">
        <div class="form-group">
          <label>Product Name *</label>
          <input type="text" formControlName="productName" class="form-control"
            [class.is-invalid]="isInvalid('productName')">
          <div class="invalid-feedback" *ngIf="isInvalid('productName')">Product name is required.</div>
        </div>

        <div class="form-group">
          <label>Category *</label>
          <select formControlName="category" class="form-control" [class.is-invalid]="isInvalid('category')">
            <option value="">Select a category</option>
            <option *ngFor="let cat of categories" [value]="cat">{{ cat }}</option>
          </select>
          <div class="invalid-feedback" *ngIf="isInvalid('category')">Category is required.</div>
        </div>

        <div class="form-group">
          <label>Price (₹) *</label>
          <input type="number" formControlName="price" class="form-control" min="0" step="0.01"
            [class.is-invalid]="isInvalid('price')">
          <div class="invalid-feedback" *ngIf="isInvalid('price')">Valid price is required.</div>
        </div>

        <div class="form-group">
          <label>Quantity *</label>
          <input type="number" formControlName="quantity" class="form-control" min="0"
            [class.is-invalid]="isInvalid('quantity')">
          <div class="invalid-feedback" *ngIf="isInvalid('quantity')">Valid quantity is required.</div>
        </div>

        <div class="form-group full-width">
          <label>Description</label>
          <textarea formControlName="description" class="form-control" rows="3"></textarea>
        </div>
      </div>

      <div class="form-actions">
        <a routerLink="/products" class="btn-cancel">Cancel</a>
        <button type="submit" class="btn-submit" [disabled]="loading || form.invalid">
          {{ loading ? 'Saving...' : 'Save Changes' }}
        </button>
      </div>
    </form>
  </div>
</main>
